module popcount8(input [7:0] a, output reg [3:0] count);
  wire [1:0] s0 = a[0] + a[1];
  wire [1:0] s1 = a[2] + a[3];
  wire [1:0] s2 = a[4] + a[5];
  wire [1:0] s3 = a[6] + a[7];
  wire [2:0] t0 = s0 + s1;
  wire [2:0] t1 = s2 + s3;
  always @(*) count = t0 + t1;
endmodule
